import React, { Component } from 'react';
import { DropdownButton, Dropdown } from 'react-bootstrap';
import { connect } from 'react-redux';
import { setCountryFilter } from '../actions/index';
import { getData, truncateData } from '../actions/index';
import {
  COUNTRY_SWITZERLAND,
  COUNTRY_FRANCE,
  COUNTRY_SPAIN,
  COUNTRY_UK
} from '../constants/action-types';

class Settings extends Component {
  setCountryFilter(filter) {
    if (filter !== this.props.countryFilter) {
      this.props.setCountryFilter(filter);
      this.props.truncateData(); // empty the user's array in memory because of new filtre
      this.props.getData(); // reload data with current filter
    }
  }

  render() {
    return (
      <>
        <DropdownButton id="dropdown-basic-button" title={`Preferred nationality: ${this.props.apiCountryFilter}`}>
          <Dropdown.Item onClick={() => this.setCountryFilter(COUNTRY_SWITZERLAND)}>
            Swiss
          </Dropdown.Item>
          <Dropdown.Item onClick={() => this.setCountryFilter(COUNTRY_SPAIN)}>
            Spanish
          </Dropdown.Item>
          <Dropdown.Item onClick={() => this.setCountryFilter(COUNTRY_FRANCE)}>
            French
          </Dropdown.Item>
          <Dropdown.Item onClick={() => this.setCountryFilter(COUNTRY_UK)}>English</Dropdown.Item>
        </DropdownButton>
      </>
    );
  }
}

function mapStateToProps(state) {
  return {
    countryFilter: state.countryFilter,
    apiCountryFilter: state.apiCountryFilter
  };
}

export default connect(
  mapStateToProps,
  { setCountryFilter, truncateData, getData }
)(Settings);
